		fprintf(stderr,"GPUassert: %s Initializing variables\n", cudaGetErrorString(error));
		exit(-1);
	}
}

__device__ __host__ inline void compute_flux_contribution(float& density, float3& momentum, float& density_energy, float& pressure, float3& velocity, float3& fc_momentum_x, float3& fc_momentum_y, float3& fc_momentum_z, float3& fc_density_energy)
{
	fc_momentum_x.x = velocity.x*momentum.x + pressure;
	fc_momentum_x.y = velocity.x*momentum.y;
	fc_momentum_x.z = velocity.x*momentum.z;

	fc_momentum_y.x = fc_momentum_x.y;
	fc_momentum_y.y = velocity.y*momentum.y + pressure;
	fc_momentum_y.z = velocity.y*momentum.z;

	fc_momentum_z.x = fc_momentum_x.z;
	fc_momentum_z.y = fc_momentum_y.z;
	fc_momentum_z.z = velocity.z*momentum.z + pressure;

	float de_p = density_energy+pressure;
	fc_density_energy.x = velocity.x*de_p;
	fc_density_energy.y = velocity.y*de_p;
	fc_density_energy.z = velocity.z*de_p;
}

__device__ inline void compute_velocity(float& density, float3& momentum, float3& velocity)
{
	velocity.x = momentum.x / density;
	velocity.y = momentum.y / density;
	velocity.z = momentum.z / density;
}

__device__ inline float compute_speed_sqd(float3& velocity)
{
	return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

__device__ inline float compute_pressure(float& density, float& density_energy, float& speed_sqd)
{
	return (float(GAMMA)-float(1.0f))*(density_energy - float(0.5f)*density*speed_sqd);
}

__device__ inline float compute_speed_of_sound(float& density, float& pressure)
{
	return sqrtf(float(GAMMA)*pressure/density);
}

__global__ void cuda_compute_step_factor(int nelr, float* variables, float* areas, float* step_factors)
{
	const int i = (blockDim.x*blockIdx.x + threadIdx.x);

	float density = variables[i + VAR_DENSITY*nelr];
	float3 momentum;
	momentum.x = variables[i + (VAR_MOMENTUM+0)*nelr];
	momentum.y = variables[i + (VAR_MOMENTUM+1)*nelr];
	momentum.z = variables[i + (VAR_MOMENTUM+2)*nelr];

	float density_energy = variables[i + VAR_DENSITY_ENERGY*nelr];
	float3 velocity;       compute_velocity(density, momentum, velocity);
	float speed_sqd      = compute_speed_sqd(velocity);
	float pressure       = compute_pressure(density, density_energy, speed_sqd);
	float speed_of_sound = compute_speed_of_sound(density, pressure);

	step_factors[i] = float(0.5f) / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
}

void compute_step_factor(int nelr, float* variables, float* areas, float* step_factors)
{
	dim3 Dg(nelr / block_length), Db(block_length);
	cuda_compute_step_factor<<<Dg, Db>>>(nelr, variables, areas, step_factors);
	cudaError_t error = cudaGetLastError();
	if (error != cudaSuccess) 
	{
		fprintf(stderr,"GPUassert: %s compute_step_factor failed\n", cudaGetErrorString(error));
		exit(-1);
	}
}

__global__ void cuda_compute_flux(int nelr, int* elements_surrounding_elements, float* normals, float* variables, float* fluxes, float ff_var_m0, float ff_var_m1, float ff_var_m2, float3 ff_fc_mx, float3 ff_fc_my, float3 ff_fc_mz, float3 ff_fc_de)
{
	const float smoothing_coefficient = float(0.2f);
	const int i = (blockDim.x*blockIdx.x + threadIdx.x);

	float data_102 = variables[i + VAR_DENSITY*nelr];
	float3 v_10;
	v_10.x = variables[i + (VAR_MOMENTUM+0)*nelr];
	v_10.y = variables[i + (VAR_MOMENTUM+1)*nelr];
	v_10.z = variables[i + (VAR_MOMENTUM+2)*nelr];

	float v_92 = variables[i + VAR_DENSITY_ENERGY*nelr];

	float3 tmp_9;             				 compute_velocity(data_102, v_10, tmp_9);
	float data_22                          = compute_speed_sqd(tmp_9);
	float x_15                              = sqrtf(data_22);
	float item_43                           = compute_pressure(data_102, v_92, data_22);
	float tmp_51                     = compute_speed_of_sound(data_102, item_43);
	float3 item_103, val_32, item_38;
	float3 data_71;
	compute_flux_contribution(data_102, v_10, v_92, item_43, tmp_9, item_103, val_32, item_38, data_71);

	float elem_53 = float(0.0f);
	float3 elem_67;
	elem_67.x = float(0.0f);
	elem_67.y = float(0.0f);
	elem_67.z = float(0.0f);
	float data_16 = float(0.0f);

	float3 data_74;
	float val_70, elem_18;
	float3 data_85;
	float3 elem_45, val_97, val_94;
	float3 v_83;
	float x_29, tmp_27, val_41;

	for(int j = 0; j < NNB; j++)
	{
		float3 v_60; float val_14;
		float data_35;

		int x_3 = elements_surrounding_elements[i + j*nelr];
		v_60.x = normals[i + (j + 0*NNB)*nelr];
		v_60.y = normals[i + (j + 1*NNB)*nelr];
		v_60.z = normals[i + (j + 2*NNB)*nelr];
		val_14 = sqrtf(v_60.x*v_60.x + v_60.y*v_60.y + v_60.z*v_60.z);

		if(0 <= x_3) 	
		{
			val_70 =        variables[x_3 + VAR_DENSITY*nelr];
			data_85.x =     variables[x_3 + (VAR_MOMENTUM+0)*nelr];
			data_85.y =     variables[x_3 + (VAR_MOMENTUM+1)*nelr];
			data_85.z =     variables[x_3 + (VAR_MOMENTUM+2)*nelr];
			elem_18 = variables[x_3 + VAR_DENSITY_ENERGY*nelr];
			compute_velocity(val_70, data_85, data_74);
			x_29                      = compute_speed_sqd(data_74);
			val_41                       = compute_pressure(val_70, elem_18, x_29);
			tmp_27                 = compute_speed_of_sound(val_70, val_41);
			compute_flux_contribution(val_70, data_85, elem_18, val_41, data_74, elem_45, val_97, val_94, v_83);

			data_35 = -val_14*smoothing_coefficient*float(0.5f)*(x_15 + sqrtf(x_29) + tmp_51 + tmp_27);
			elem_53 = elem_53 + (data_35*(data_102-val_70));
			data_16 = data_16 + (data_35*(v_92-elem_18));
			elem_67.x += data_35*(v_10.x-data_85.x);
			elem_67.y += data_35*(v_10.y-data_85.y);
			elem_67.z += data_35*(v_10.z-data_85.z);

			data_35 = float(0.5f)*v_60.x;
			elem_53 = elem_53 + (data_35*(data_85.x+v_10.x));
			data_16 = data_16 + (data_35*(v_83.x+data_71.x));
			elem_67.x += data_35*(elem_45.x+item_103.x);
			elem_67.y += data_35*(val_97.x+val_32.x);
			elem_67.z += data_35*(val_94.x+item_38.x);

			data_35 = float(0.5f)*v_60.y;
			elem_53 = elem_53 + (data_35*(data_85.y+v_10.y));
			data_16 = data_16 + (data_35*(v_83.y+data_71.y));
			elem_67.x += data_35*(elem_45.y+item_103.y);
			elem_67.y += data_35*(val_97.y+val_32.y);
			elem_67.z += data_35*(val_94.y+item_38.y);

			data_35 = float(0.5f)*v_60.z;
			elem_53 = elem_53 + (data_35*(data_85.z+v_10.z));
			data_16 = data_16 + (data_35*(v_83.z+data_71.z));
			elem_67.x += data_35*(elem_45.z+item_103.z);
			elem_67.y += data_35*(val_97.z+val_32.z);
			elem_67.z += data_35*(val_94.z+item_38.z);
		}
		else if(-1 == x_3)	
		{
			elem_67.x += v_60.x*item_43;
			elem_67.y += v_60.y*item_43;
			elem_67.z += v_60.z*item_43;
		}
		else if(-2 == x_3) 
		{
			data_35 = float(0.5f)*v_60.x;
			elem_53 = elem_53 + (data_35*(ff_var_m0+v_10.x));
			data_16 = data_16 + (data_35*(ff_fc_de.x+data_71.x));
			elem_67.x += data_35*(ff_fc_mx.x + item_103.x);
			elem_67.y += data_35*(ff_fc_my.x + val_32.x);
			elem_67.z += data_35*(ff_fc_mz.x + item_38.x);

			data_35 = float(0.5f)*v_60.y;
			elem_53 = elem_53 + (data_35*(ff_var_m1+v_10.y));
			data_16 = data_16 + (data_35*(ff_fc_de.y+data_71.y));
			elem_67.x += data_35*(ff_fc_mx.y + item_103.y);
			elem_67.y += data_35*(ff_fc_my.y + val_32.y);
			elem_67.z += data_35*(ff_fc_mz.y + item_38.y);

			data_35 = float(0.5f)*v_60.z;
			elem_53 = elem_53 + (data_35*(ff_var_m2+v_10.z));
			data_16 = data_16 + (data_35*(ff_fc_de.z+data_71.z));
			elem_67.x += data_35*(ff_fc_mx.z + item_103.z);
			elem_67.y += data_35*(ff_fc_my.z + val_32.z);
			elem_67.z += data_35*(ff_fc_mz.z + item_38.z);
		}
	}
	fluxes[i + VAR_DENSITY*nelr] = elem_53;
	fluxes[i + (VAR_MOMENTUM+0)*nelr] = elem_67.x;
	fluxes[i + (VAR_MOMENTUM+1)*nelr] = elem_67.y;
	fluxes[i + (VAR_MOMENTUM+2)*nelr] = elem_67.z;
	fluxes[i + VAR_DENSITY_ENERGY*nelr] = data_16;
}

