__global__ void cuda_time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes)
{
	const int i = (blockDim.x*blockIdx.x + threadIdx.x);
	float item_24 = step_factors[i]/float(RK+1-j);

	variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + item_24*fluxes[i + VAR_DENSITY*nelr];
	variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + item_24*fluxes[i + (VAR_MOMENTUM+0)*nelr];
	variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + item_24*fluxes[i + (VAR_MOMENTUM+1)*nelr];
	variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + item_24*fluxes[i + (VAR_MOMENTUM+2)*nelr];
	variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + item_24*fluxes[i + VAR_DENSITY_ENERGY*nelr];
}

void time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes)
{
	dim3 Dg(nelr / block_length), Db(block_length);
	cuda_time_step<<<Dg,Db>>>(j, nelr, old_variables, variables, step_factors, fluxes);
	cudaError_t error = cudaGetLastError();
	if (error != cudaSuccess) 
	{
		fprintf(stderr,"GPUassert: %s update failed\n", cudaGetErrorString(error));
		exit(-1);
	}
}

int main(int argc, char** argv)
{
	if (argc < 2)
	{
		std::cout << "specify data file name" << std::endl;
		return 0;
	}
	const char* tmp_69 = argv[1];

	float ff_variable_h[NVAR];
	float3 ff_flux_contribution_momentum_x_h, ff_flux_contribution_momentum_y_h, ff_flux_contribution_momentum_z_h, ff_flux_contribution_density_energy_h;

	{
		const float data_55 = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

		ff_variable_h[VAR_DENSITY] = float(1.4);

		float elem_73 = float(1.0f);
		float x_59 = sqrtf(GAMMA*elem_73 / ff_variable_h[VAR_DENSITY]);
		float v_6 = float(ff_mach)*x_59;

		float3 var_40;
		var_40.x = v_6*float(cos((float)data_55));
		var_40.y = v_6*float(sin((float)data_55));
		var_40.z = 0.0f;

		ff_variable_h[VAR_MOMENTUM+0] = ff_variable_h[VAR_DENSITY] * var_40.x;
		ff_variable_h[VAR_MOMENTUM+1] = ff_variable_h[VAR_DENSITY] * var_40.y;
		ff_variable_h[VAR_MOMENTUM+2] = ff_variable_h[VAR_DENSITY] * var_40.z;

		ff_variable_h[VAR_DENSITY_ENERGY] = ff_variable_h[VAR_DENSITY]*(float(0.5f)*(v_6*v_6)) + (elem_73 / float(GAMMA-1.0f));

		float3 v_2;
		v_2.x = *(ff_variable_h+VAR_MOMENTUM+0);
		v_2.y = *(ff_variable_h+VAR_MOMENTUM+1);
		v_2.z = *(ff_variable_h+VAR_MOMENTUM+2);
		compute_flux_contribution(ff_variable_h[VAR_DENSITY], v_2, ff_variable_h[VAR_DENSITY_ENERGY], elem_73, var_40, ff_flux_contribution_momentum_x_h, ff_flux_contribution_momentum_y_h, ff_flux_contribution_momentum_z_h, ff_flux_contribution_density_energy_h);
	}
	int val_77;
	int nelr;

	float* areas;
	int* elements_surrounding_elements;
	float* normals;
	{
		std::ifstream v_11(tmp_69);

		v_11 >> val_77;
		nelr = block_length*((val_77 / block_length )+ std::min(1, val_77 % block_length));

		float* h_areas = new float[nelr];
		int* h_elements_surrounding_elements = new int[nelr*NNB];
		float* h_normals = new float[NDIM*NNB*nelr];

		for(int i = 0; val_77 > i; i++)
		{
			v_11 >> h_areas[i];
			for(int j = 0; NNB > j; j++)
			{
				v_11 >> h_elements_surrounding_elements[i + j*nelr];
				if(0 > h_elements_surrounding_elements[i+j*nelr]) h_elements_surrounding_elements[i+j*nelr] = -1;
				h_elements_surrounding_elements[i + j*nelr]--; 

				for(int k = 0; NDIM > k; k++)
				{
					v_11 >>  h_normals[i + (j + k*NNB)*nelr];
					h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
				}
			}
		}

		int item_82 = val_77-1;
		for(int i = val_77; nelr > i; i++)
		{
			h_areas[i] = h_areas[item_82];
			for(int j = 0; NNB > j; j++)
			{
				h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[item_82 + j*nelr];
				for(int k = 0; NDIM > k; k++) h_normals[i + (j + k*NNB)*nelr] = h_normals[item_82 + (j + k*NNB)*nelr];
			}
		}

		areas = alloc<float>(nelr);
		upload<float>(areas, h_areas, nelr);

		elements_surrounding_elements = alloc<int>(nelr*NNB);
		upload<int>(elements_surrounding_elements, h_elements_surrounding_elements, nelr*NNB);

		normals = alloc<float>(NDIM*NNB*nelr);
		upload<float>(normals, h_normals, NDIM*NNB*nelr);

		delete[] h_areas;
		delete[] h_elements_surrounding_elements;
		delete[] h_normals;
	}

	float* variables = alloc<float>(nelr*NVAR);
	initialize_variables(nelr, variables);

	float* old_variables = alloc<float>(nelr*NVAR);
	float* fluxes = alloc<float>(nelr*NVAR);
	float* step_factors = alloc<float>(nelr);

	std::cout << "Starting..." << std::endl;

	checkCudaErrors( cudaMemcpyToSymbol(ff_variable,          ff_variable_h,          NVAR*sizeof(float)) );
	checkCudaErrors( cudaMemcpyToSymbol(ff_flux_contribution_momentum_x, &ff_flux_contribution_momentum_x_h, sizeof(float3)) );
	checkCudaErrors( cudaMemcpyToSymbol(ff_flux_contribution_momentum_y, &ff_flux_contribution_momentum_y_h, sizeof(float3)) );
	checkCudaErrors( cudaMemcpyToSymbol(ff_flux_contribution_momentum_z, &ff_flux_contribution_momentum_z_h, sizeof(float3)) );
	checkCudaErrors( cudaMemcpyToSymbol(ff_flux_contribution_density_energy, &ff_flux_contribution_density_energy_h, sizeof(float3)) );

	StopWatchInterface *timer = NULL;
	sdkCreateTimer(&timer);
	sdkStartTimer(&timer);

	for(int i = 0; i < iterations; i++)
	{
		copy<float>(old_variables, variables, nelr*NVAR);

		compute_step_factor(nelr, variables, areas, step_factors);

		for(int j = 0; j < RK; j++)
		{
			compute_flux(nelr, elements_surrounding_elements, normals, variables, fluxes, 
				ff_variable_h[VAR_MOMENTUM+0], ff_variable_h[VAR_MOMENTUM+1], ff_variable_h[VAR_MOMENTUM+2],
				ff_flux_contribution_momentum_x_h, ff_flux_contribution_momentum_y_h, ff_flux_contribution_momentum_z_h, ff_flux_contribution_density_energy_h);
			time_step(j, nelr, old_variables, variables, step_factors, fluxes);
		}
	}

	sdkStopTimer(&timer);
	std::cout  << (sdkGetAverageTimerValue(&timer)/1000.0)  / iterations << " seconds per iteration" << std::endl;

	std::cout << "Saving solution..." << std::endl;
	dump(variables, val_77, nelr);
	std::cout << "Saved solution..." << std::endl;

	std::cout << "Cleaning up..." << std::endl;
	dealloc<float>(areas);
	dealloc<int>(elements_surrounding_elements);
	dealloc<float>(normals);

	dealloc<float>(variables);
	dealloc<float>(old_variables);
	dealloc<float>(fluxes);
	dealloc<float>(step_factors);

	std::cout << "Done..." << std::endl;

	return 0;
}
